      "name": "p4w_weeks_cte",
      "purpose": "Determine the 4 distinct weeks immediately preceding the R4W window (P4W), non-overlapping.",
      "logic": "Find boundary_week = MIN(week_end_date) from r4w_weeks_cte; from distinct_weeks_cte select week_end_date < boundary_week, order by week_end_date DESC, keep top 4."
